import React, { useState } from 'react';
import './App.css';

function App() {
    const [tokenId, setTokenId] = useState('');
    const [selectedAssets, setSelectedAssets] = useState([]);

    const assets = ["Hat", "Glasses", "Scarf"]; // Example assets

    const handleTokenChange = (event) => {
        setTokenId(event.target.value);
    };

    const handleAssetChange = (asset) => {
        const newSelectedAssets = selectedAssets.includes(asset)
            ? selectedAssets.filter(a => a !== asset) // Remove asset
            : [...selectedAssets, asset]; // Add asset
        setSelectedAssets(newSelectedAssets);
    };

    const handleSubmit = () => {
        console.log('Token ID Submitted:', tokenId);
        console.log('Selected Assets:', selectedAssets);
        // Add logic to send tokenId and selectedAssets to Flask backend
    };

    return (
        <div className="App">
            <header className="App-header">
                <input type="text" placeholder="Enter Token ID" value={tokenId} onChange={handleTokenChange} />
                <button onClick={handleSubmit}>Submit</button>
                <div>
                    {assets.map(asset => (
                        <div key={asset}>
                            <input
                                type="checkbox"
                                id={asset}
                                name={asset}
                                checked={selectedAssets.includes(asset)}
                                onChange={() => handleAssetChange(asset)}
                            />
                            <label htmlFor={asset}>{asset}</label>
                        </div>
                    ))}
                </div>
                {/* Placeholder for asset display */}
                <div id="asset-display">
                    <p>Selected assets will be displayed here</p>
                </div>
            </header>
        </div>
    );
}

export default App;
